    {"title":"Binary Search","description":"Implement binary search on a sorted list. Return index of target, or -1 if not found.","story":"A million scrolls in the dragon's lair. Search smart or lose.","difficulty":Difficulty.hard,"game_mode":GameMode.battle,"language":Language.python,"level_req":1,"starter_code":"def binary_search(arr, target):\n    left, right = 0, len(arr) - 1\n    pass","solution":"def binary_search(arr, target):\n    left, right = 0, len(arr)-1\n    while left <= right:\n        mid = (left+right)//2\n        if arr[mid]==target: return mid\n        elif arr[mid]<target: left=mid+1\n        else: right=mid-1\n    return -1","test_cases":[{"input":[[1,3,5,7,9],5],"expected_output":"2"},{"input":[[1,3,5,7,9],6],"expected_output":"-1"},{"input":[[2,4,6,8,10],10],"expected_output":"4"}],"hints":["mid = (left+right)//2","If target > arr[mid], search right","If target < arr[mid], search left"],"xp_reward":500,"time_limit":600},
    {"title":"Two Sum","description":"Return sorted indices of two numbers that add up to target.","story":None,"difficulty":Difficulty.hard,"game_mode":GameMode.puzzle,"language":Language.python,"level_req":1,"starter_code":"def two_sum(nums, target):\n    pass","solution":"def two_sum(nums, target):\n    seen={}\n    for i,n in enumerate(nums):\n        comp=target-n\n        if comp in seen: return sorted([seen[comp],i])\n        seen[n]=i\n    return []","test_cases":[{"input":[[2,7,11,15],9],"expected_output":"[0, 1]"},{"input":[[3,2,4],6],"expected_output":"[1, 2]"},{"input":[[3,3],6],"expected_output":"[0, 1]"}],"hints":["Use a hash map","For each number look for complement","complement = target - current"],"xp_reward":500,"time_limit":600},
