def seed():
    Base.metadata.create_all(bind=engine)
    db = SessionLocal()
    try:
        existing = db.query(Challenge).count()
        if existing > 0:
            print(f"Already {existing} challenges exist. Skipping seed.")
            return
        for data in CHALLENGES:
            db.add(Challenge(**data))
        db.commit()
        print(f"Seeded {len(CHALLENGES)} challenges successfully!")
    finally:
        db.close()

if __name__ == "__main__":
    seed()
